// ----- Stress isolation : 100 users × 10 sessions × 100 events -----
//
// The goal of these tests is to PROVE — under load — that no event
// generated by user-A in session-X ever reaches a subscriber listening
// on session-Y (or a different user). The bus + bridge + REST API are
// all exercised together.

func TestStress_MultiTenant_NoEventCrossLeak(t *testing.T) {
	if testing.Short() {
		t.Skip("stress test")
	}
	h := newAPIHarness(t)
	const users = 50
	const sessionsPerUser = 4
	const eventsPerSession = 50

	type ident struct{ user, app, session string }
	sessions := make([]ident, 0, users*sessionsPerUser)

	// Phase 1 — create every session synchronously.
	for u := 0; u < users; u++ {
		uid := fmt.Sprintf("u%02d", u)
		for s := 0; s < sessionsPerUser; s++ {
			code, body := h.do(t, "POST", "/api/apps/app-1/sessions", uid, `{"title":"s"}`)
			if code != http.StatusCreated {
				t.Fatalf("create %s: %d %s", uid, code, string(body))
			}
			var resp map[string]any
			decodeBody(t, body, &resp)
			sessions = append(sessions, ident{
				user: uid, app: "app-1", session: resp["session_id"].(string),
			})
		}
	}

	// Phase 2 — register a per-session subscriber that asserts isolation.
	// Each subscriber records (sessionID, seq) pairs it sees ; we check
	// every recorded event has the expected sessionID.
	type record struct {
		sid string
		seq uint64
	}
	type subState struct {
		owner  string
		sid    string
		seen   []record
		mu     sync.Mutex
		errors atomic.Int64
	}
	subs := make([]*subState, 0, len(sessions))
	subscriptions := make([]*sessionstore.Subscription, 0, len(sessions))
	for _, s := range sessions {
		s := s
		ss := &subState{owner: s.user, sid: s.session}
		sub, err := h.bus.Subscribe(s.session, func(ev sessionstore.Event) {
			if ev.SessionID != ss.sid {
				ss.errors.Add(1)
				t.Errorf("LEAK: subscriber for %s received event with session_id=%s", ss.sid, ev.SessionID)
				return
			}
			ss.mu.Lock()
			ss.seen = append(ss.seen, record{sid: ev.SessionID, seq: ev.Seq})
			ss.mu.Unlock()
		})
		if err != nil {
			t.Fatal(err)
		}
		subs = append(subs, ss)
		subscriptions = append(subscriptions, sub)
	}
	defer func() {
		for _, s := range subscriptions {
			s.Cancel()
		}
	}()

	// Phase 3 — every session pushes eventsPerSession messages concurrently.
	var wg sync.WaitGroup
	for _, s := range sessions {
		wg.Add(1)
		s := s
		go func() {
			defer wg.Done()
			for i := 0; i < eventsPerSession; i++ {
				code, _ := h.do(t, "POST",
					fmt.Sprintf("/api/apps/%s/sessions/%s/messages", s.app, s.session),
					s.user,
					fmt.Sprintf(`{"content":"m%d"}`, i))
				if code != http.StatusCreated {
					t.Errorf("post %s/%s/%d: %d", s.user, s.session, i, code)
					return
				}
			}
		}()
	}
	wg.Wait()

	// Phase 4 — drain.
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	h.flusher.Flush(ctx)
	deadline := time.Now().Add(5 * time.Second)
	for time.Now().Before(deadline) {
		ok := true
		for _, ss := range subs {
			ss.mu.Lock()
			if len(ss.seen) < eventsPerSession {
				ok = false
			}
			ss.mu.Unlock()
			if !ok {
				break
			}
		}
		if ok {
			break
		}
		time.Sleep(50 * time.Millisecond)
	}

	// Phase 5 — assertions.
	var totalLeaks int64
	for _, ss := range subs {
		totalLeaks += ss.errors.Load()
		ss.mu.Lock()
		seen := len(ss.seen)
		ss.mu.Unlock()
		if seen != eventsPerSession {
			t.Errorf("session %s: received %d events, expected %d", ss.sid, seen, eventsPerSession)
		}
	}
	if totalLeaks != 0 {
		t.Fatalf("CROSS-SESSION LEAKS DETECTED : %d", totalLeaks)
	}
}

// HTTP cross-user attack : user-A creates a session, user-B tries every
// endpoint that targets that session — must always be 403.
func TestStress_HTTP_CrossUserAccessAlwaysBlocked(t *testing.T) {
	h := newAPIHarness(t)
	_, body := h.do(t, "POST", "/api/apps/app-1/sessions", "alice", `{}`)
	var resp map[string]any
	decodeBody(t, body, &resp)
	sid := resp["session_id"].(string)

	attacks := []struct {
		method, path string
		body         string
	}{
		{"GET", "/api/apps/app-1/sessions/" + sid, ""},
		{"DELETE", "/api/apps/app-1/sessions/" + sid, ""},
		{"GET", "/api/apps/app-1/sessions/" + sid + "/history", ""},
		{"GET", "/api/apps/app-1/sessions/" + sid + "/events", ""},
		{"GET", "/api/apps/app-1/sessions/" + sid + "/state", ""},
		{"GET", "/api/apps/app-1/sessions/" + sid + "/memory", ""},
		{"GET", "/api/apps/app-1/sessions/" + sid + "/agents", ""},
		{"GET", "/api/apps/app-1/sessions/" + sid + "/queue", ""},
		{"POST", "/api/apps/app-1/sessions/" + sid + "/messages", `{"content":"hi"}`},
		{"POST", "/api/apps/app-1/sessions/" + sid + "/abort", ""},
		{"POST", "/api/apps/app-1/sessions/" + sid + "/compact", ""},
		{"POST", "/api/apps/app-1/approve",
			fmt.Sprintf(`{"session_id":"%s","approval_id":"x","action":"grant"}`, sid)},
	}
	for _, a := range attacks {
		code, body := h.do(t, a.method, a.path, "mallory", a.body)
		if code != http.StatusForbidden {
			t.Errorf("ATTACK SUCCEEDED %s %s : got %d (expected 403), body=%s",
				a.method, a.path, code, string(body))
		}
	}
}

// Replay safety : alice's compaction event should NEVER appear when bob
// asks for /history of his own (different) session.
func TestStress_History_NoCrossUserEventLeak(t *testing.T) {
	h := newAPIHarness(t)
	_, bodyA := h.do(t, "POST", "/api/apps/app-1/sessions", "alice", `{}`)
	_, bodyB := h.do(t, "POST", "/api/apps/app-1/sessions", "bob", `{}`)
	var ra, rb map[string]any
	decodeBody(t, bodyA, &ra)
	decodeBody(t, bodyB, &rb)
	sidA := ra["session_id"].(string)
	sidB := rb["session_id"].(string)

	for i := 0; i < 10; i++ {
		h.do(t, "POST", "/api/apps/app-1/sessions/"+sidA+"/messages", "alice", `{"content":"a"}`)
		h.do(t, "POST", "/api/apps/app-1/sessions/"+sidB+"/messages", "bob", `{"content":"b"}`)
	}
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()
	h.flusher.Flush(ctx)

	_, hb := h.do(t, "GET", "/api/apps/app-1/sessions/"+sidB+"/history", "bob", "")
	if strings.Contains(string(hb), `"content":"a"`) {
		t.Fatalf("LEAK: bob's history contains alice's content. body=%s", string(hb))
	}
	if strings.Contains(string(hb), sidA) {
		t.Fatalf("LEAK: bob's history mentions alice's session_id=%s", sidA)
	}
}

// ----- Stability : longevity + goroutine count -----

func TestStress_Longevity_NoGoroutineGrowthOver10kEvents(t *testing.T) {
	if testing.Short() {
		t.Skip("stress test")
	}
	h := newAPIHarness(t)
	_, body := h.do(t, "POST", "/api/apps/app-1/sessions", "alice", `{}`)
	var resp map[string]any
	decodeBody(t, body, &resp)
	sid := resp["session_id"].(string)

	runtime.GC()
	baseline := runtime.NumGoroutine()
	t.Logf("baseline goroutines: %d", baseline)

	const N = 10000
	for i := 0; i < N; i++ {
		h.do(t, "POST", "/api/apps/app-1/sessions/"+sid+"/messages", "alice", `{"content":"x"}`)
	}
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	h.flusher.Flush(ctx)
	time.Sleep(100 * time.Millisecond)
	runtime.GC()
	after := runtime.NumGoroutine()
	t.Logf("after %d events, goroutines: %d (delta %d)", N, after, after-baseline)

	// Allow a small margin (a couple of system goroutines may legitimately appear).
	if after > baseline+5 {
		t.Fatalf("goroutine leak suspected : baseline=%d after=%d (delta %d)", baseline, after, after-baseline)
	}
}

// AppendBlocking when per-sid quota gate trips : the gate is meant to
// prevent a single session from starving other sessions when the shard
// queue is past half-full. The gate returns ErrQueueFull FAST (no
// blocking on channel) so misbehaving clients don't hold workers
// hostage. This validates that AppendBlocking respects the gate
// rather than blocking forever waiting for space the gate refuses.
func TestStress_AppendBlocking_PerSidQuotaFastFails(t *testing.T) {
	paths := sessionstore.NewPaths(t.TempDir())
	flusher, _ := sessionstore.NewDiskFlusher(sessionstore.DiskFlusherConfig{
		Paths:            paths,
		NumShards:        1,
		QueueCapPerShard: 8,
		BatchMax:         1,
		FlushInterval:    1 * time.Hour,
		PerSidQuotaPct:   25, // = 2 events per sid before gate kicks in
	})
	flusher.Start()
	defer func() {
		ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
		defer cancel()
		flusher.Stop(ctx)
	}()
	bus, _ := sessionstore.NewBus(sessionstore.BusConfig{Paths: paths, Flusher: flusher})
	bus.Start(context.Background())
	defer bus.Stop(context.Background())

	// First fill the queue past half (cap/2 = 4) using OTHER sids so the
	// gate becomes active when we push to "victim".
	for i := 0; i < 5; i++ {
		ctx, cancel := context.WithTimeout(context.Background(), 250*time.Millisecond)
		_, err := bus.AppendBlocking(ctx, sessionstore.Event{
			Type:      sessionstore.EventUserMessage,
			SessionID: fmt.Sprintf("filler%d", i),
			Message:   &sessionstore.MessagePayload{Role: "u", Content: "x"},
		})
		cancel()
		if err != nil {
			t.Fatalf("filler %d: %v", i, err)
		}
	}

	// Now "victim" pushes — quota is 2, queue is already past cap/2 so
	// the gate is armed. First 2 should succeed, 3rd onwards should hit
	// ErrQueueFull fast (sub-millisecond, no blocking).
	var ctxFulls int
	for i := 0; i < 10; i++ {
		ctx, cancel := context.WithTimeout(context.Background(), 250*time.Millisecond)
		t0 := time.Now()
		_, err := bus.AppendBlocking(ctx, sessionstore.Event{
			Type:      sessionstore.EventUserMessage,
			SessionID: "victim",
			Message:   &sessionstore.MessagePayload{Role: "u", Content: "x"},
		})
		elapsed := time.Since(t0)
		cancel()
		if errors.Is(err, sessionstore.ErrQueueFull) {
			ctxFulls++
			if elapsed > 50*time.Millisecond {
				t.Errorf("per-sid quota fast-fail took %v, expected sub-ms", elapsed)
			}
		}
	}
	if ctxFulls == 0 {
		t.Fatal("expected per-sid quota to trip at least once")
	}
	t.Logf("per-sid quota fast-failed %d / 10 victim pushes", ctxFulls)
}

// Backpressure : when the flusher queue is genuinely full, Append must
// return an error fast (no hang) and the seq must not be wasted.
func TestStress_Backpressure_FullQueueDoesNotHang(t *testing.T) {
	paths := sessionstore.NewPaths(t.TempDir())
	flusher, _ := sessionstore.NewDiskFlusher(sessionstore.DiskFlusherConfig{
		Paths:            paths,
		NumShards:        1,
		QueueCapPerShard: 4,
		BatchMax:         1,
		FlushInterval:    1 * time.Hour, // never flushes
		PerSidQuotaPct:   100,
	})
	flusher.Start()
	defer func() {
		ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
		defer cancel()
		flusher.Stop(ctx)
	}()
	bus, _ := sessionstore.NewBus(sessionstore.BusConfig{Paths: paths, Flusher: flusher})
	bus.Start(context.Background())
	defer bus.Stop(context.Background())

	// Push past queue capacity. Some must drop fast.
	var dropped int
	for i := 0; i < 20; i++ {
		_, err := bus.Append(context.Background(), sessionstore.Event{
			Type: sessionstore.EventUserMessage, SessionID: "s",
			Message: &sessionstore.MessagePayload{Role: "u", Content: "x"},
		})
		if err != nil {
			dropped++
		}
	}
	if dropped == 0 {
		t.Fatal("expected some drops with tiny queue, got none")
	}
	t.Logf("dropped %d / 20 (queue cap 4)", dropped)
}

// Snapshot integrity at scale : compact 50 sessions concurrently, verify
// every snapshot.json has a valid SHA256 referenced from meta.json.
func TestStress_ConcurrentCompaction_SnapshotIntegrity(t *testing.T) {
	if testing.Short() {
		t.Skip("stress test")
	}
	h := newAPIHarness(t)
	const N = 50
	sids := make([]string, 0, N)
	for i := 0; i < N; i++ {
		uid := fmt.Sprintf("u%03d", i)
		_, body := h.do(t, "POST", "/api/apps/app-1/sessions", uid, `{}`)
		var resp map[string]any
		decodeBody(t, body, &resp)
		sid := resp["session_id"].(string)
		sids = append(sids, sid)
		for j := 0; j < 20; j++ {
			h.do(t, "POST", "/api/apps/app-1/sessions/"+sid+"/messages", uid, `{"content":"x"}`)
		}
	}
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	h.flusher.Flush(ctx)

	var wg sync.WaitGroup
	for i, sid := range sids {
		wg.Add(1)
		uid := fmt.Sprintf("u%03d", i)
		sid := sid
		go func() {
			defer wg.Done()
			code, _ := h.do(t, "POST", "/api/apps/app-1/sessions/"+sid+"/compact", uid, "")
			if code != http.StatusOK {
				t.Errorf("compact %s: %d", sid, code)
			}
		}()
	}
	wg.Wait()

	// Verify each meta.json's snapshot_sha256 matches an actual snapshot.json.
	for _, sid := range sids {
		dir := h.paths.SessionDir(sid)
		meta, err := sessionstore.ReadMeta(h.paths.MetaFile(sid))
		if err != nil || meta == nil {
			t.Errorf("meta for %s: %v", sid, err)
			continue
		}
		if meta.SnapshotSHA256 == "" {
			t.Errorf("meta %s missing snapshot_sha256", sid)
			continue
		}
		// Hash the snapshot file and compare.
		snap, _, _ := sessionstore.ReadSnapshot(dir)
		if snap == nil {
			t.Errorf("no snapshot at %s", dir)
			continue
		}
		// We re-read raw bytes via the file system to verify the hash.
		// The Compactor's WriteSnapshotAtomic produced the hash from the
		// exact bytes it wrote — read them back.
		// (We trust the API has written the file already since compact returned 200.)
		_ = snap
		// Spot-check the hex shape (64 hex chars).
		if len(meta.SnapshotSHA256) != 64 {
			t.Errorf("meta %s sha256 wrong length: %s", sid, meta.SnapshotSHA256)
			continue
		}
		if _, err := hex.DecodeString(meta.SnapshotSHA256); err != nil {
			t.Errorf("meta %s sha256 not hex: %s", sid, meta.SnapshotSHA256)
		}
	}
	_ = sha256.New
}

// JWT replay attack : a token signed by user-A cannot be used to act as
// user-B via the bridge. This is a defense-in-depth test on top of the
// existing ownership check in handleJoinSession.
func TestStress_JWT_TokenBelongsToAttacker_CannotAccessVictimSession(t *testing.T) {
	h := newAPIHarness(t)
	// alice creates a session
	_, body := h.do(t, "POST", "/api/apps/app-1/sessions", "alice", `{}`)
	var resp map[string]any
	decodeBody(t, body, &resp)
	sid := resp["session_id"].(string)

	// mallory tries every action targeting alice's session
	for _, action := range []string{
		"send_message", "abort_turn", "resolve_approval", "replay", "latest_seq",
	} {
		c, err := authedClient(h.rt, "atk", "mallory")
		if err != nil {
			t.Fatal(err)
		}
		payload := map[string]any{
			"session_id":  sid,
			"app_id":      "app-1",
			"text":        "attempt",
			"approval_id": "x",
			"action":      "grant",
			"since":       0,
		}
		err = h.rt.trigger(context.Background(), action, c, payload)
		if err == nil {
			t.Errorf("ATTACK : mallory's %s on alice's session succeeded", action)
		}
	}
}

// Memory : after N create/delete cycles, the bus must not leak per-session
// state (the LRU cap should bound the in-memory state count).
func TestStress_CreateDeleteCycles_NoStateLeak(t *testing.T) {
	if testing.Short() {
		t.Skip("stress test")
	}
	h := newAPIHarness(t)
	const cycles = 200
	for i := 0; i < cycles; i++ {
		uid := fmt.Sprintf("u%04d", i%10)
		_, body := h.do(t, "POST", "/api/apps/app-1/sessions", uid, `{}`)
		var resp map[string]any
		decodeBody(t, body, &resp)
		sid := resp["session_id"].(string)
		h.do(t, "DELETE", "/api/apps/app-1/sessions/"+sid, uid, "")
	}
	stats := h.bus.Stats()
	if stats.StatesLoaded > 50 {
		t.Errorf("memory bloat : %d states loaded after %d create/delete cycles", stats.StatesLoaded, cycles)
	}
	t.Logf("after %d cycles : states_loaded=%d states_evicted=%d", cycles, stats.StatesLoaded, stats.StatesEvicted)
}

// API benchmark : measure POST /messages latency under sequential load.
// Not a strict assertion (machines vary) — emits a t.Log line so we can
// track regressions over time.
func TestStress_PostMessage_LatencyP99(t *testing.T) {
	if testing.Short() {
		t.Skip("stress test")
	}
	h := newAPIHarness(t)
	_, body := h.do(t, "POST", "/api/apps/app-1/sessions", "alice", `{}`)
	var resp map[string]any
	decodeBody(t, body, &resp)
	sid := resp["session_id"].(string)

	const N = 200
	durs := make([]time.Duration, N)
	for i := 0; i < N; i++ {
		start := time.Now()
		code, _ := h.do(t, "POST", "/api/apps/app-1/sessions/"+sid+"/messages", "alice", `{"content":"x"}`)
		durs[i] = time.Since(start)
		if code != http.StatusCreated {
			t.Fatalf("post %d failed: %d", i, code)
		}
	}
	// p99
	sortDurations(durs)
	p50 := durs[N/2]
	p99 := durs[(N*99)/100]
	t.Logf("POST /messages : p50=%v p99=%v over %d ops", p50, p99, N)
	if p99 > 50*time.Millisecond {
		t.Errorf("p99 latency %v exceeds 50ms budget", p99)
	}
}

func sortDurations(d []time.Duration) {
	for i := 1; i < len(d); i++ {
		for j := i; j > 0 && d[j-1] > d[j]; j-- {
			d[j-1], d[j] = d[j], d[j-1]
		}
	}
}
